1	// app/tests/db-helpers.ts — DB test infrastructure for the writeback / transition / dispute cycles.
2	//
3	// freshDb() gives each test an isolated in-memory database with the schema applied.
4	// seedWorld() inserts the reference data (member + active policy + coverage rules) a claim needs.
5	// makeClaimService() is the composition root: it wires the repositories + service over one Db.
6	
7	import { type Db, type DbHandle, createDb } from "../src/db/connection";
8	import { applySchema } from "../src/db/migrate";
9	import { coverageRules, members, policies } from "../src/db/schema";
10	import type { CoverageRule } from "../src/domain/types";
11	import { createAccumulatorRepository } from "../src/repositories/accumulator.repository";
12	import { createAdjudicationRepository } from "../src/repositories/adjudication.repository";
13	import { createClaimRepository } from "../src/repositories/claim.repository";
14	import { createCoverageRuleRepository } from "../src/repositories/coverage-rule.repository";
15	import { createDisputeRepository } from "../src/repositories/dispute.repository";
16	import { createPolicyRepository } from "../src/repositories/policy.repository";
17	import { createStatusTransitionRepository } from "../src/repositories/status-transition.repository";
18	import {
19	  type ClaimServiceDeps,
20	  createClaimService,
21	} from "../src/services/claim.service";
22	import {
23	  type DisputeServiceDeps,
24	  createDisputeService,
25	} from "../src/services/dispute.service";
26	import { createSetStatus } from "../src/services/set-status";
27	
28	export function freshDb() {
29	  const handle = createDb(":memory:");
30	  applySchema(handle.sqlite);
31	  return handle;
32	}
33	
34	export function makeClaimService(
35	  handle: DbHandle,
36	  overrides: Partial<ClaimServiceDeps> = {},
37	) {
38	  const { db, sqlite } = handle;
39	  const claims = createClaimRepository(db);
40	  const statusTransitions = createStatusTransitionRepository(db);
41	  return createClaimService({
42	    claims,
43	    adjudications: createAdjudicationRepository(db),
44	    accumulators: createAccumulatorRepository(db),
45	    coverageRules: createCoverageRuleRepository(db),
46	    policies: createPolicyRepository(db),
47	    setStatus: createSetStatus({ claims, statusTransitions }),
48	    // one transaction per claim — better-sqlite3 wraps every statement on this connection
49	    withTransaction: <T>(fn: () => T): T => sqlite.transaction(fn)(),
50	    ...overrides,
51	  });
52	}
53	
54	export function makeDisputeService(
55	  handle: DbHandle,
56	  overrides: Partial<DisputeServiceDeps> = {},
57	) {
58	  const { db, sqlite } = handle;
59	  const claims = createClaimRepository(db);
60	  const statusTransitions = createStatusTransitionRepository(db);
61	  return createDisputeService({
62	    claims,
63	    adjudications: createAdjudicationRepository(db),
64	    accumulators: createAccumulatorRepository(db),
65	    coverageRules: createCoverageRuleRepository(db),
66	    policies: createPolicyRepository(db),
67	    disputes: createDisputeRepository(db),
68	    setStatus: createSetStatus({ claims, statusTransitions }),
69	    withTransaction: <T>(fn: () => T): T => sqlite.transaction(fn)(),
70	    ...overrides,
71	  });
72	}
73	
74	export function makeSetStatus(handle: DbHandle) {
75	  const { db } = handle;
76	  return createSetStatus({
77	    claims: createClaimRepository(db),
78	    statusTransitions: createStatusTransitionRepository(db),
79	  });
80	}
81	
82	type SeedRule = Partial<CoverageRule> & { serviceCode: string };
83	
84	// Insert a member + an active 2026 policy + coverage rules. Returns the ids a claim needs.
85	export function seedWorld(
86	  db: Db,
87	  opts: { deductibleCents?: number; oopMaxCents?: number; rules: SeedRule[] },
88	) {
89	  const memberId = "mem_seed_1";
90	  const policyId = "pol_seed_1";
91	  const planYear = "2026";
92	
93	  db.insert(members)
94	    .values({ id: memberId, name: "Jane Doe", dob: "1990-05-01" })
95	    .run();
96	  db.insert(policies)
97	    .values({
98	      id: policyId,
99	      memberId,
100	      planYear,
101	      effectiveDate: "2026-01-01",
102	      terminationDate: "2026-12-31",
103	      deductibleCents: opts.deductibleCents ?? 50_000,
104	      oopMaxCents: opts.oopMaxCents ?? 300_000,
105	    })
106	    .run();
107	
108	  opts.rules.forEach((r, i) => {
109	    const costShare = r.costShare ?? { type: "full_coverage" };
110	    const limit = r.limit ?? { unit: "none" };
111	    db.insert(coverageRules)
112	      .values({
113	        id: `cr_seed_${i}`,
114	        policyId,
115	        serviceCode: r.serviceCode,
116	        covered: r.covered ?? true,
117	        excluded: r.excluded ?? false,
118	        costShareType: costShare.type,
119	        copayCents: costShare.type === "copay" ? costShare.copayCents : null,
120	        coinsuranceRate:
121	          costShare.type === "coinsurance" ? costShare.rate : null,
122	        appliesDeductible: r.appliesDeductible ?? false,
123	        limitUnit: limit.unit,
124	        limitAmountCents: limit.unit === "dollars" ? limit.amountCents : null,
125	        limitCount: limit.unit === "visits" ? limit.count : null,
126	        requiresPriorAuth: r.requiresPriorAuth ?? false,
127	      })
