export type ValidationIssue = { field: string; code: string; message: string };

// The subset of an ajv error object we read. Fastify exposes these on `error.validation`.
type RawValidationError = {
  keyword?: string;
  instancePath?: string;
  message?: string;
  params?: Record<string, unknown>;
};

// "/lineItems/0/billedCents" → "lineItems.0.billedCents"; "" → "".
function pathToField(instancePath: string): string {
  return instancePath.replace(/^\//, "").replace(/\//g, ".");
}

function fieldOf(err: RawValidationError): string {
  // A missing required property reports the parent path; name the absent field itself.
  if (
    err.keyword === "required" &&
    typeof err.params?.missingProperty === "string"
  ) {
    const base = pathToField(err.instancePath ?? "");
    return base
      ? `${base}.${err.params.missingProperty}`
      : err.params.missingProperty;
  }
  return pathToField(err.instancePath ?? "") || "body";
}

export function formatValidationErrors(
  validation: RawValidationError[],
): ValidationIssue[] {
  return validation.map((err) => ({
    field: fieldOf(err),
    code: err.keyword ?? "invalid",
    message: err.message ?? "invalid value",
  }));
}

// app/src/middlewares/error-handler.ts — the one central error handler for the API.
//
// Two jobs: (1) turn schema-validation failures into the PRD intake reject — 400 with
// { errors: [{ field, code, message }] }; (2) fail closed on anything unexpected with 500.
// Domain DECISIONS (denials) are never errors — they return 200 from the service. Identity/state
// errors that DO map to 4xx (e.g. a dispute on a missing line) are handled at their controller.

import type {
  FastifyError,
  FastifyInstance,
  FastifyReply,
  FastifyRequest,
} from "fastify";
import { formatValidationErrors } from "./schema-validation";

export function registerErrorHandler(app: FastifyInstance): void {
  app.setErrorHandler(
    (error: FastifyError, _request: FastifyRequest, reply: FastifyReply) => {
      if (error.validation) {
        return reply
          .code(400)
          .send({ errors: formatValidationErrors(error.validation) });
      }

      const status =
        typeof error.statusCode === "number" &&
        error.statusCode >= 400 &&
        error.statusCode < 500
          ? error.statusCode
          : 500;
      return reply
        .code(status)
        .send({ error: { code: error.code ?? "INTERNAL_ERROR", message: error.message } });
    },
  );
}

