2	//
3	// A SERVICE holds business logic / workflows; it depends on REPOSITORIES (which own the Db and
4	// encapsulate all data access), never on the raw connection. Layering: service → repositories → db.
5	// Every status change routes through the injected setStatus() chokepoint (status column + transition
6	// log in one write). The one-transaction-per-claim boundary is an injected withTransaction runner.
7	
8	import { adjudicateLine } from "../domain/adjudication/adjudicator";
9	import type { ClaimStatus } from "../domain/entities/claim";
10	import {
11	  type LineOutcome,
12	  aggregateClaimStatus,
13	} from "../domain/state-machines/claim-state";
14	import type { AccumulatorRepository } from "../repositories/accumulator.repository";
15	import type { AdjudicationRepository } from "../repositories/adjudication.repository";
16	import type { ClaimRepository } from "../repositories/claim.repository";
17	import type { CoverageRuleRepository } from "../repositories/coverage-rule.repository";
18	import type { PolicyRepository } from "../repositories/policy.repository";
19	import type { SetStatus } from "./set-status";
20	
21	export type ClaimServiceDeps = {
22	  claims: ClaimRepository;
23	  adjudications: AdjudicationRepository;
24	  accumulators: AccumulatorRepository;
25	  coverageRules: CoverageRuleRepository;
26	  policies: PolicyRepository;
27	  setStatus: SetStatus;
28	  withTransaction: <T>(fn: () => T) => T;
29	};
30	
31	export type AdjudicateClaimInput = {
32	  memberId: string;
33	  serviceDate: string;
34	  provider?: string;
35	  diagnosisCode?: string;
36	  lineItems: {
37	    serviceCode: string;
38	    billedCents: number;
39	    units?: number;
40	    priorAuthPresent?: boolean;
41	  }[];
42	};
43	
44	export type AdjudicateClaimResult = { claimId: string; status: ClaimStatus };
45	
46	export function createClaimService(deps: ClaimServiceDeps) {
47	  function adjudicateClaim(input: AdjudicateClaimInput): AdjudicateClaimResult {
48	    return deps.withTransaction(() => {
49	      const policy = deps.policies.findActiveForMember(
50	        input.memberId,
51	        input.serviceDate,
52	      );
53	      if (!policy) {
54	        throw new Error(
55	          `no active policy for member ${input.memberId} on ${input.serviceDate}`,
56	        );
57	      }
58	      const planYear = String(policy.planYear);
59	      const ruleByService = new Map(
60	        deps.coverageRules
61	          .findByPolicy(policy.id)
62	          .map((r) => [r.serviceCode, r]),
63	      );
64	
65	      const claimId = deps.claims.insertClaim({
66	        memberId: input.memberId,
67	        policyId: policy.id,
68	        serviceDate: input.serviceDate,
69	        provider: input.provider ?? null,
70	        diagnosisCode: input.diagnosisCode ?? null,
71	      });
72	      deps.setStatus({
73	        claimId,
74	        target: { type: "CLAIM", status: "SUBMITTED" },
75	        fromStatus: null,
76	        actor: "SYSTEM",
77	        reason: "SUBMIT",
78	      });
79	
80	      // Phase 1 — persist + submit every line (PENDING).
81	      const submitted = input.lineItems.map((li) => {
82	        const fingerprint = `${input.memberId}|${li.serviceCode}|${input.serviceDate}|${li.billedCents}`;
83	        const line = deps.claims.insertLine(claimId, {
84	          serviceCode: li.serviceCode,
85	          billedCents: li.billedCents,
86	          units: li.units,
87	          priorAuthPresent: li.priorAuthPresent,
88	          fingerprint,
89	        });
90	        deps.setStatus({
91	          claimId,
92	          target: { type: "LINE_ITEM", id: line.id, status: "PENDING" },
93	          fromStatus: null,
94	          actor: "SYSTEM",
95	          reason: "SUBMIT",
96	        });
97	        return { line, fingerprint };
98	      });
99	
100	      // Phase 2 — adjudicate each line in order. One snapshot at claim start; deltas are applied to
101	      // this working copy between lines so a later line sees an earlier line's draw (determinism).
102	      const acc = deps.accumulators.snapshot(input.memberId, planYear);
103	      const touched = {
104	        deductible: false,
105	        oop: false,
106	        limits: new Set<string>(),
107	      };
108	      const outcomes: LineOutcome[] = [];
109	
110	      for (const { line, fingerprint } of submitted) {
111	        const result = adjudicateLine({
112	          line: {
113	            id: line.id,
114	            claimId,
115	            serviceCode: line.serviceCode,
116	            billedCents: line.billedCents,
117	            units: line.units,
118	            priorAuthPresent: line.priorAuthPresent,
119	            status: "PENDING",
120	            fingerprint,
121	          },
122	          policy,
123	          rule: ruleByService.get(line.serviceCode),
124	          serviceDate: input.serviceDate,
125	          acc: {
126	            deductibleMetCents: acc.deductibleMetCents,
127	            oopMetCents: acc.oopMetCents,
128	            limitUsed: acc.limitUsedByService[line.serviceCode] ?? 0,
129	          },
130	          alreadyAdjudicated: false,
131	        });
132	
133	        // adjudicateLine only ever decides APPROVED | DENIED (never PENDING/NEEDS_REVIEW)
134	        const newStatus = result.status as "APPROVED" | "DENIED";
135	        deps.adjudications.append({
